final:
module RefModule(
    input clk,
    input reset,
    input [4:0] in,
    output reg [4:0] out);

    reg [4:0] obf_in_last;

    always @(posedge clk) begin
        if (reset)
            out <= 5'b0;
        else begin
            obf_in_last <= in;
            out <= out | (~obf_in_last & in);
        end
    end
endmodule
